/* setFile */
INSERT INTO TM_FILEXM(
            FILE_NUMB
          , ORIG_NAME
          , STOR_NAME
          , FILE_PATH
          , FILE_SIZE
          , MIME_TYPE
          , REGI_USER
          , REGI_DATE
) VALUES (
            #{fileNumb}
          , #{origName}
          , #{storName}
          , #{filePath}
          , #{fileSize}
          , #{mimeType}
          , #{regiUser,jdbcType=NUMERIC}
          , SYSDATE
)
